(globalThis.TURBOPACK||(globalThis.TURBOPACK=[])).push(["object"==typeof document?document.currentScript:void 0,59544,e=>{"use strict";var a=e.i(43476),t=e.i(22016),i=e.i(75157);let n={primary:"bg-accent text-accent-on font-bold hover:bg-accent-deep active:scale-[0.985] shadow-soft hover:shadow-card",accent:"bg-accent text-accent-on font-bold hover:bg-accent-deep active:scale-[0.985] shadow-soft",ink:"bg-ink text-paper font-semibold hover:bg-[#1d2c40] active:scale-[0.985] shadow-soft",outline:"border border-hairline-strong bg-card text-ink font-semibold hover:border-ink-faint hover:bg-paper active:scale-[0.985]",ghost:"text-ink-soft font-semibold hover:bg-paper-2 hover:text-ink active:scale-[0.985]",danger:"bg-rhodo text-white font-bold hover:bg-rhodo-deep active:scale-[0.985] shadow-soft",inverse:"bg-dusk-text text-dusk font-bold hover:bg-white active:scale-[0.985] shadow-dusk",luxury:"bg-gold-tint text-gold-ink font-bold border border-gold/30 hover:bg-gold hover:text-white active:scale-[0.985]"},r={sm:"h-11 px-3.5 text-[0.8125rem] gap-1.5 rounded-sm",md:"h-11 px-5 text-sm gap-2 rounded-md",lg:"h-12 px-6 text-[0.9375rem] gap-2 rounded-md",xl:"h-14 px-7 text-base gap-2.5 rounded-lg"},o="inline-flex select-none items-center justify-center whitespace-nowrap transition-all duration-200 disabled:pointer-events-none disabled:opacity-45";e.s(["Button",0,function({variant:e="primary",size:t="md",className:s,children:l,...h}){return(0,a.jsx)("button",{className:(0,i.cn)(o,n[e],r[t],s),...h,children:l})},"ButtonLink",0,function({variant:e="primary",size:s="md",className:l,children:h,...d}){return(0,a.jsx)(t.default,{className:(0,i.cn)(o,n[e],r[s],l),...d,children:h})}])},86563,e=>{"use strict";let a=(0,e.i(56420).default)("star",[["path",{d:"M11.525 2.295a.53.53 0 0 1 .95 0l2.31 4.679a2.123 2.123 0 0 0 1.595 1.16l5.166.756a.53.53 0 0 1 .294.904l-3.736 3.638a2.123 2.123 0 0 0-.611 1.878l.882 5.14a.53.53 0 0 1-.771.56l-4.618-2.428a2.122 2.122 0 0 0-1.973 0L6.396 21.01a.53.53 0 0 1-.77-.56l.881-5.139a2.122 2.122 0 0 0-.611-1.879L2.16 9.795a.53.53 0 0 1 .294-.906l5.165-.755a2.122 2.122 0 0 0 1.597-1.16z",key:"r04s7s"}]]);e.s(["Star",0,a],86563)},91323,e=>{"use strict";let a=(0,e.i(56420).default)("badge-check",[["path",{d:"M3.85 8.62a4 4 0 0 1 4.78-4.77 4 4 0 0 1 6.74 0 4 4 0 0 1 4.78 4.78 4 4 0 0 1 0 6.74 4 4 0 0 1-4.77 4.78 4 4 0 0 1-6.75 0 4 4 0 0 1-4.78-4.77 4 4 0 0 1 0-6.76Z",key:"3c2336"}],["path",{d:"m9 12 2 2 4-4",key:"dzmm74"}]]);e.s(["BadgeCheck",0,a],91323)},7219,e=>{"use strict";let a=(0,e.i(56420).default)("trending-up",[["path",{d:"M16 7h6v6",key:"box55l"}],["path",{d:"m22 7-8.5 8.5-5-5L2 17",key:"1t1m79"}]]);e.s(["TrendingUp",0,a],7219)},52832,e=>{"use strict";let a=[{id:"r1",entity:"trek:everest-base-camp",author:"Hannah M.",country:"Germany",rating:5,date:"2026-04-18",text:"The acclimatisation schedule is the product. Two friends on a cheaper itinerary turned back at Lobuche; our group of six all made Kala Patthar. Pasang checked our oxygen every evening like clockwork.",tags:["safety-first","well-paced"]},{id:"r2",entity:"trek:everest-base-camp",author:"Daniel O.",country:"USA",rating:5,date:"2026-03-30",text:"Booked the whole thing from the app in one evening: guide, permits, gear kit, even the flight buffer day saved us when Lukla fogged in. The QR check-in at lodges felt like the future.",tags:["seamless booking"]},{id:"r3",entity:"trek:everest-base-camp",author:"Priya S.",country:"India",rating:4,date:"2025-11-12",text:"Strenuous but organised beautifully. Only wish I'd taken the porter add-on from day one instead of adding it in Namche (which the app let me do, thankfully, in about two minutes).",tags:["add-ons-flexible"]},{id:"r4",entity:"trek:mardi-himal",author:"Tom W.",country:"UK",rating:5,date:"2026-04-02",text:"Did this in a long weekend from Pokhara. High Camp sunset had grown men silent. The gear kit was waiting at the Lakeside shop exactly as the app promised, fitted, paid, out in 15 minutes.",tags:["short & mighty"]},{id:"r5",entity:"trek:mardi-himal",author:"Lena K.",country:"Netherlands",rating:5,date:"2026-03-15",text:"Our guide Sarita timed the summit push so we had the viewpoint nearly alone before the crowd. Rhododendrons were absurd. Cried a little. Five stars.",tags:["sunrise","spring bloom"]},{id:"r6",entity:"trek:annapurna-circuit",author:"Marco B.",country:"Italy",rating:5,date:"2025-10-28",text:"Thorong La at dawn is the hardest, best morning of my life. The app's altitude warnings actually adjusted when I logged a headache in Manang. It added a rest day and rebooked the lodges automatically.",tags:["dynamic replanning","safety-first"]},{id:"r7",entity:"trek:annapurna-circuit",author:"Aiko T.",country:"Japan",rating:5,date:"2026-04-22",text:"Every lodge knew we were coming. Marpha's apple brandy is dangerous after three weeks of no alcohol. The fairness checker said 5% below average, checked two agencies, it was true.",tags:["honest pricing"]},{id:"r8",entity:"trek:langtang-valley",author:"Sophie R.",country:"France",rating:5,date:"2026-05-04",text:"Tenzing told us the valley's story over three days. By Kyanjin I understood what we were walking through. The cheese factory tour ended in a tasting that derailed our schedule pleasantly.",tags:["culture-rich"]},{id:"r9",entity:"trek:poon-hill",author:"The Andersons",country:"Australia",rating:5,date:"2026-01-09",text:"Took our kids (8 and 11). Anita was a magician with them: games on the steps, hot chocolate timed exactly at whine o'clock. Sunrise was crowded and completely worth it.",tags:["family-friendly"]},{id:"r18",entity:"trek:manaslu-circuit",author:"Erik H.",country:"Norway",rating:5,date:"2025-11-05",text:"It really is Annapurna thirty years ago: teahouses, no crowds, prayer wheels older than the trail signs. The restricted-area permits were just ready when we landed; I never once saw the paperwork. Larkya La is no joke, but the pacing got all six of us over.",tags:["wild & quiet","permit-handled"]},{id:"r19",entity:"trek:manaslu-circuit",author:"Camille D.",country:"France",rating:5,date:"2026-04-08",text:"The Samdo rest day the app insisted on is why I made the pass. Two trekkers from another agency skipped theirs and turned back at Dharamsala. Worth every rupee for the acclimatisation logic alone.",tags:["safety-first","serious pass"]},{id:"r20",entity:"trek:rara-lake",author:"Will T.",country:"UK",rating:5,date:"2025-10-20",text:"Three days with no signal and by day two I'd stopped reaching for my phone. The lake colour you see in photos is real. I genuinely didn't believe it until Rara was in front of me. Bluest water in Nepal, and we had the shore to ourselves.",tags:["digital detox","remote"]},{id:"r21",entity:"trek:rara-lake",author:"Yuki N.",country:"Japan",rating:4,date:"2026-05-18",text:"Our Talcha flight slipped a day in the weather; the buffer the app built in absorbed it without touching the rest of the plan. Remote and quiet, the most peaceful nights I've had on any trek.",tags:["flight buffer","remote"]},{id:"r10",entity:"guide:pasang-norbu-sherpa",author:"Hannah M.",country:"Germany",rating:5,date:"2026-04-18",text:"Calm, funny, ruthless about rest steps. He spotted the early AMS signs of a trekker in another group and probably saved their trip.",tags:[]},{id:"r11",entity:"guide:anita-gurung",author:"The Andersons",country:"Australia",rating:5,date:"2026-01-09",text:"Our kids still talk about her. Knows every aunt in every village. Book her months ahead.",tags:[]},{id:"r12",entity:"guide:tenzing-lama",author:"Sophie R.",country:"France",rating:5,date:"2026-05-04",text:"A historian with crampons. The butter-tea ceremony at his cousin's lodge was the trip's quiet highlight.",tags:[]},{id:"r13",entity:"stay:courtyard-of-patan",author:"James L.",country:"Canada",rating:5,date:"2026-02-14",text:"Woke to temple bells, breakfast in the courtyard, walked to Durbar Square before the buses. Rooms are snug (heritage means heritage) but I'd never stay anywhere else in the valley.",tags:[]},{id:"r14",entity:"stay:amas-homestay-ghandruk",author:"Lena K.",country:"Netherlands",rating:5,date:"2026-03-16",text:"Ama fed us four rounds of daal bhaat and taught us to say 'pugyo!' (enough!), useful too late. The view from the bed is real.",tags:[]},{id:"r15",entity:"stay:lakeside-pavilion-pokhara",author:"Marco B.",country:"Italy",rating:5,date:"2025-11-01",text:"Post-circuit recovery here was the best money of the trip. Floated in the pool staring at the mountain I'd just walked around.",tags:[]},{id:"r16",entity:"gear:down-jacket-8000",author:"Daniel O.",country:"USA",rating:5,date:"2026-03-30",text:"Warmer than my friend's brand-new jacket that cost 6x the rental. Smelled like nothing, which for rental down is a miracle.",tags:[]},{id:"r17",entity:"kit:everest-kit",author:"Hannah M.",country:"Germany",rating:5,date:"2026-04-18",text:"Fitted everything in 20 minutes in Thamel, returned it in Lukla. RETURNED IT IN LUKLA. Why does anyone buy gear for one trek?",tags:[]}];e.s(["reviewStats",0,function(e){let t=a.filter(a=>a.entity===e);return t.length?{count:t.length,avg:t.reduce((e,a)=>e+a.rating,0)/t.length}:{count:0,avg:0}}])},76853,e=>{"use strict";var a=e.i(43476),t=e.i(75157),i=e.i(52832),n=e.i(91323),r=e.i(86563);let o=(0,e.i(56420).default)("trending-down",[["path",{d:"M16 17h6v-6",key:"t6n2it"}],["path",{d:"m22 17-8.5-8.5-5 5L2 7",key:"x473p"}]]);var s=e.i(7219),l=e.i(84026);function h({value:e,count:i,className:n}){return(0,a.jsxs)("span",{className:(0,t.cn)("inline-flex items-center gap-1 text-[0.8125rem] font-bold text-ink",n),children:[(0,a.jsx)(r.Star,{className:"h-3.5 w-3.5 fill-accent text-accent-ink"}),(0,a.jsx)("span",{className:"data-mono",children:e.toFixed(1)}),void 0!==i&&(0,a.jsxs)("span",{className:"font-medium text-ink-mute",children:["(",i.toLocaleString(),")"]})]})}e.s(["Chip",0,function({active:e=!1,className:i,children:n,...r}){return(0,a.jsx)("button",{type:"button","aria-pressed":e,className:(0,t.cn)("relative inline-flex h-9 shrink-0 items-center gap-1.5 rounded-full border px-3.5 text-[0.8125rem] font-semibold transition-all duration-150 before:absolute before:-inset-y-1.5 before:inset-x-0 before:content-['']",e?"border-ink bg-ink text-paper shadow-soft":"border-hairline-strong bg-card text-ink-soft hover:border-ink-faint hover:text-ink",i),...r,children:n})},"EntityRating",0,function({entity:e,className:n}){let{count:r,avg:o}=(0,i.reviewStats)(e);return 0===r?(0,a.jsx)("span",{className:(0,t.cn)("text-[0.8125rem] font-bold text-ink-mute",n),children:"New"}):(0,a.jsx)(h,{value:o,count:r,className:n})},"FairnessChip",0,function({deltaPct:e,context:i="for this route & season",className:n}){let r=e<=0;return(0,a.jsxs)("span",{className:(0,t.cn)("inline-flex items-center gap-1.5 rounded-full px-2.5 py-1 text-xs font-bold",r?"bg-juniper-tint text-juniper-deep":"bg-accent-tint text-accent-ink",n),title:`AI price check: ${Math.abs(e)}% ${r?"below":"above"} the market average ${i}`,children:[r?(0,a.jsx)(o,{className:"h-3.5 w-3.5",strokeWidth:2.5}):(0,a.jsx)(s.TrendingUp,{className:"h-3.5 w-3.5",strokeWidth:2.5}),Math.abs(e),"% ",r?"below":"above"," average"]})},"Rating",0,h,"Tag",0,function({tone:e="neutral",className:i,children:n}){return(0,a.jsx)("span",{className:(0,t.cn)("inline-flex items-center gap-1 rounded-full px-2.5 py-1 text-xs font-bold",{neutral:"bg-paper-2 text-ink-soft",marigold:"bg-accent-tint text-accent-ink",juniper:"bg-juniper-tint text-juniper-deep",rhodo:"bg-rhodo-tint text-rhodo-deep",glacier:"bg-glacier-tint text-glacier-deep",gold:"bg-gold-tint text-gold-ink",ink:"bg-ink text-paper"}[e],i),children:n})},"TrustScore",0,function({score:e,className:i,detail:n}){return(0,a.jsxs)("span",{className:(0,t.cn)("inline-flex items-center gap-1.5 text-xs font-bold text-juniper-deep",i),title:n??"Trust score from verification, reviews and on-trip record",children:[(0,a.jsx)(l.ShieldCheck,{className:"h-3.5 w-3.5",strokeWidth:2.5}),(0,a.jsx)("span",{className:"data-mono",children:e}),(0,a.jsx)("span",{className:"font-semibold text-ink-mute",children:"trust"})]})},"VerifiedBadge",0,function({label:e="Verified",className:i}){return(0,a.jsxs)("span",{className:(0,t.cn)("inline-flex items-center gap-1 rounded-full bg-juniper-tint px-2.5 py-1 text-xs font-bold text-juniper-deep",i),children:[(0,a.jsx)(n.BadgeCheck,{className:"h-3.5 w-3.5",strokeWidth:2.5}),e]})}],76853)},99508,e=>{"use strict";let a=[{slug:"everest-base-camp",name:"Everest Base Camp",nameNe:"सगरमाथा आधार शिविर",region:"Khumbu",days:12,difficulty:"demanding",maxAltitude:5545,distanceKm:130,bestMonths:"Mar–May · Oct–Nov",permits:[{name:"Sagarmatha National Park entry",npr:3e3},{name:"Khumbu Pasang Lhamu municipality fee",npr:2e3}],category:"trek",priceMode:"from",priceFromNpr:175e3,meetPoint:"Lukla airstrip",whatThisIsNot:"This is not a solitude trek: in peak season the trail is a procession, teahouse beds sell out, and Lukla flights can strand you for a day or two.",operatorId:"op-khumbu",summary:"Twelve days through Sherpa country to the foot of the world's highest mountain, and the sunrise of your life from Kala Patthar.",story:"The Khumbu doesn't ease you in: the flight to Lukla lands on a runway tilted into a hillside, and from there the trail climbs through pine forest, across swaying suspension bridges, into a world where every village has a gompa and every ridge a view of Ama Dablam. You walk slowly (that's the whole skill) sleeping twice in Namche and twice in Dingboche so your blood learns the altitude. The reward is standing in the amphitheatre of the Khumbu Icefall, and the next dawn watching Everest turn marigold from Kala Patthar.",highlights:["Sunrise on Everest from Kala Patthar (5,545 m)","Two acclimatisation days built in: Namche & Dingboche","Tengboche monastery at dusk, prayer chants included","The Hillary Suspension Bridge above Dudh Koshi","Sherpa bakeries in Namche: yes, real cinnamon rolls"],profile:[{day:1,m:2860,label:"Lukla"},{day:1.5,m:2610,label:"Phakding"},{day:2,m:3440,label:"Namche"},{day:3,m:3880,label:"Everest View"},{day:3.5,m:3440},{day:4,m:3860,label:"Tengboche"},{day:5,m:4410,label:"Dingboche"},{day:6,m:5083,label:"Nangkartshang"},{day:6.5,m:4410},{day:7,m:4940,label:"Lobuche"},{day:8,m:5364,label:"Base Camp"},{day:8.5,m:5164,label:"Gorak Shep"},{day:9,m:5545,label:"Kala Patthar"},{day:9.5,m:4371,label:"Pheriche"},{day:10,m:3440,label:"Namche"},{day:11,m:2860,label:"Lukla"},{day:12,m:1400,label:"Kathmandu"}],itinerary:[{day:1,title:"Fly to Lukla, walk to Phakding",km:8,hours:"3–4 h",sleepAltitude:2610,note:"The famous 30-minute flight, then a gentle warm-up descent along the Dudh Koshi. Don't rush, your body starts adapting today."},{day:2,title:"Phakding → Namche Bazaar",km:11,hours:"6 h",sleepAltitude:3440,note:"Five suspension bridges and the long Namche hill. First glimpse of Everest if the sky is kind."},{day:3,title:"Acclimatisation in Namche",km:5,hours:"3 h",sleepAltitude:3440,note:"Hike high, sleep low: Everest View Hotel (3,880 m) for tea, back down for the night. Visit the Sherpa Culture Museum."},{day:4,title:"Namche → Tengboche",km:10,hours:"5 h",sleepAltitude:3860,note:"Contour trail with Ama Dablam ahead all afternoon. Evening prayers at the monastery are open to guests."},{day:5,title:"Tengboche → Dingboche",km:11,hours:"5–6 h",sleepAltitude:4410,note:"Above the treeline now. The valley opens wide and the air gets noticeably thinner."},{day:6,title:"Acclimatisation in Dingboche",km:5,hours:"4 h",sleepAltitude:4410,note:"Climb Nangkartshang ridge (5,083 m) slowly, then rest. Headache that won't quit? Tell your guide. Today, not tomorrow."},{day:7,title:"Dingboche → Lobuche",km:8.5,hours:"5 h",sleepAltitude:4940,note:"Past the climbers' memorials at Thukla Pass, a quiet, important place. Short steps, steady breathing."},{day:8,title:"Lobuche → Base Camp via Gorak Shep",km:13,hours:"7–8 h",sleepAltitude:5164,note:"Drop bags in Gorak Shep, then the rocky walk to Base Camp itself (5,364 m). The Icefall cracks and groans. You'll hear it."},{day:9,title:"Kala Patthar sunrise → Pheriche",km:12,hours:"7 h",sleepAltitude:4371,note:"Pre-dawn start, –10 °C, completely worth it: the only place Everest's summit fills the sky. Then a long, happy descent."},{day:10,title:"Pheriche → Namche",km:15,hours:"6–7 h",sleepAltitude:3440,note:"Thick air feels like a luxury. Celebrate with a bakery stop."},{day:11,title:"Namche → Lukla",km:19,hours:"7 h",sleepAltitude:2860,note:"The last bridges, one final hill into Lukla, and a toast with your crew."},{day:12,title:"Fly back to Kathmandu",sleepAltitude:1400,note:"Morning flight out (weather permitting, we build in a buffer). Hot shower, big dinner, done."}],route:[{lat:27.687,lng:86.731,label:"Lukla"},{lat:27.804,lng:86.71,label:"Namche"},{lat:27.836,lng:86.764,label:"Tengboche"},{lat:27.892,lng:86.831,label:"Dingboche"},{lat:27.948,lng:86.81,label:"Lobuche"},{lat:28.003,lng:86.853,label:"Base Camp"}],teahouses:!0,safetyNote:"Altitude is the real risk here, not the trail. Our itinerary follows the golden rule, never raise your sleeping altitude by more than ~500 m above 3,000 m, and your guide carries a pulse oximeter and checks you twice daily.",fitnessNote:"You should be comfortable walking 5–7 hours with a daypack on consecutive days. No climbing skills needed. It's a walk, just a high one.",palette:"dawn",rating:4.9,reviews:412,fairnessDeltaPct:-8,kitSlug:"everest-kit"},{slug:"annapurna-circuit",name:"Annapurna Circuit",nameNe:"अन्नपूर्ण परिक्रमा",region:"Annapurna",days:10,difficulty:"demanding",maxAltitude:5416,distanceKm:112,bestMonths:"Mar–Apr · Oct–Nov",permits:[{name:"Annapurna Conservation Area permit",npr:3e3},{name:"TIMS card",npr:2e3}],category:"trek",priceMode:"from",priceFromNpr:152e3,meetPoint:"Besisahar jeep stand",whatThisIsNot:"This is not the road-free circuit of the postcards: jeep tracks now shadow long sections, and the quiet lives in the side valleys and the high crossing, not on the main line.",operatorId:"op-annapurna",summary:"The classic horseshoe around the Annapurna massif: subtropical valleys to the wind-scoured pass of Thorong La at 5,416 m.",story:"No trek in Nepal changes worlds like the Circuit. You start among rice terraces and waterfalls, climb through pine and juniper into the Tibetan-Buddhist high desert of Manang, and finish by crossing Thorong La before dawn, prayer flags snapping in the wind. Then, absurdly, you descend to Muktinath, sacred to two religions at once, and the apple orchards of Marpha. It is the best ten-day education in Himalayan geography that exists.",highlights:["Crossing Thorong La (5,416 m) at first light","Manang's medieval lanes and the Ice Lake day-hike","Muktinath: 108 water spouts and an eternal flame","Apple brandy in Marpha, the prettiest village in Mustang","Big-wall views: Annapurna II, Gangapurna, Tilicho"],profile:[{day:1,m:2710,label:"Chame"},{day:2,m:3300,label:"Upper Pisang"},{day:3,m:3540,label:"Manang"},{day:4,m:4600,label:"Ice Lake"},{day:4.5,m:3540},{day:5,m:4050,label:"Yak Kharka"},{day:6,m:4450,label:"Thorong Phedi"},{day:7,m:5416,label:"Thorong La"},{day:7.5,m:3800,label:"Muktinath"},{day:8,m:2720,label:"Jomsom"},{day:9,m:822,label:"Pokhara"},{day:10,m:822,label:"Rest day"}],itinerary:[{day:1,title:"Drive Kathmandu → Chame",sleepAltitude:2710,note:"A long jeep day up the Marsyangdi gorge: waterfalls, cliff roads, hot springs near the lodge if you have energy."},{day:2,title:"Chame → Upper Pisang",km:14,hours:"5 h",sleepAltitude:3300,note:"The Paungda Danda rock wall curves above you like a frozen wave. Take the upper village for the views."},{day:3,title:"Upper Pisang → Manang",km:17,hours:"6–7 h",sleepAltitude:3540,note:"High route via Ghyaru and Ngawal: harder, drier, and the best mountain balconies on the circuit."},{day:4,title:"Acclimatisation in Manang",km:8,hours:"5 h",sleepAltitude:3540,note:"Ice Lake (4,600 m) is a proper outing: 1,000 m up, 1,000 m down, perfect acclimatisation. Bakeries and a tiny cinema in town."},{day:5,title:"Manang → Yak Kharka",km:9,hours:"4 h",sleepAltitude:4050,note:"Short day by design. Watch for blue sheep on the slopes, and snow leopards watch for them."},{day:6,title:"Yak Kharka → Thorong Phedi",km:7,hours:"3–4 h",sleepAltitude:4450,note:"Early lunch, early sleep. Phedi means 'foot of the hill'. Tomorrow you climb it."},{day:7,title:"Thorong La (5,416 m) → Muktinath",km:16,hours:"8–9 h",sleepAltitude:3800,note:"Start ~4 a.m. by headlamp. Tea shack halfway, prayer flags at the top, then a 1,600 m descent into another climate."},{day:8,title:"Muktinath → Jomsom",km:18,hours:"5–6 h",sleepAltitude:2720,note:"Temple visit at dawn, then down the Kali Gandaki, the world's deepest gorge, and its windiest afternoon. Lunch in Marpha."},{day:9,title:"Fly Jomsom → Pokhara",sleepAltitude:822,note:"Twenty minutes over the gorge you just walked. Lakeside dinner, legs up."},{day:10,title:"Pokhara rest day",sleepAltitude:822,note:"Boat to the Tal Barahi temple, massage, or absolutely nothing. You've earned the nothing."}],route:[{lat:28.232,lng:84.378,label:"Besisahar"},{lat:28.555,lng:84.242,label:"Chame"},{lat:28.666,lng:84.014,label:"Manang"},{lat:28.794,lng:83.937,label:"Thorong La"},{lat:28.817,lng:83.872,label:"Muktinath"},{lat:28.78,lng:83.723,label:"Jomsom"}],teahouses:!0,safetyNote:"Thorong La is a long, cold, early day. The itinerary stages you properly at Yak Kharka and Phedi first, and your guide will call a rest day in Manang if your oxygen saturation says so. In winter the pass can close; we re-route via Jomsom when it does.",fitnessNote:"Good general fitness required: one 8–9 hour summit day, several 6-hour days. Hiking poles strongly recommended for the long descent.",palette:"alpenglow",rating:4.8,reviews:367,fairnessDeltaPct:-5,kitSlug:"annapurna-kit"},{slug:"mardi-himal",name:"Mardi Himal",nameNe:"मार्दी हिमाल",region:"Annapurna",days:4,difficulty:"moderate",maxAltitude:4500,distanceKm:35,bestMonths:"Mar–May · Oct–Dec",permits:[{name:"Annapurna Conservation Area permit",npr:3e3},{name:"TIMS card",npr:2e3}],category:"trek",priceMode:"from",priceFromNpr:54e3,meetPoint:"Kande roadhead, Pokhara",whatThisIsNot:"This is not a gentle beginner stroll: the ridge days are steep and weather-exposed, and High Camp nights are cold even in spring.",operatorId:"op-annapurna",summary:"Four days on a rhododendron ridge straight at the Fishtail: the best short trek in Nepal, and still strangely quiet.",story:"Mardi is what trekkers recommend to friends in a low voice, hoping it stays uncrowded. From Pokhara you're in forest within an hour (moss, ferns, red rhododendron in spring) and the whole route simply follows one rising ridge. Each morning the wall of Machhapuchhre is closer, until at Base Camp it fills half the sky. Down in two days via stone villages where the daal bhaat is cooked on wood fires.",highlights:["Machhapuchhre (Fishtail) close enough to touch","Rhododendron tunnels in March–April","Sunrise at 4,500 m without a single permit queue","Siding village descent: old Nepal, no road noise","Doable in a long weekend from Pokhara"],profile:[{day:1,m:2520,label:"Forest Camp"},{day:2,m:3580,label:"High Camp"},{day:3,m:4500,label:"Base Camp"},{day:3.5,m:2970,label:"Low Camp"},{day:4,m:822,label:"Pokhara"}],itinerary:[{day:1,title:"Pokhara → Kande → Forest Camp",km:9,hours:"5 h",sleepAltitude:2520,note:"Short drive, then up through Australian Camp into deep forest. Listen for langur monkeys around dusk."},{day:2,title:"Forest Camp → High Camp",km:8,hours:"5 h",sleepAltitude:3580,note:"You break the treeline mid-afternoon and the ridge reveals itself. Sunset here is the trip's first jaw-drop."},{day:3,title:"Base Camp sunrise → Low Camp",km:11,hours:"7 h",sleepAltitude:2970,note:"3:30 a.m. headlamps to Base Camp (4,500 m) for sunrise on Mardi, Machhapuchhre and Annapurna South. Long descent after breakfast."},{day:4,title:"Low Camp → Siding → Pokhara",km:7,hours:"4 h",sleepAltitude:822,note:"Stone steps into Siding village, jeep along the river, Lakeside by mid-afternoon."}],route:[{lat:28.3,lng:83.82,label:"Kande"},{lat:28.36,lng:83.86,label:"Forest Camp"},{lat:28.41,lng:83.89,label:"High Camp"},{lat:28.45,lng:83.92,label:"Base Camp"}],teahouses:!0,safetyNote:"The summit morning gains a lot of height quickly. If you feel altitude symptoms at High Camp, the view from there is already worth the trip. Don't push past a headache.",fitnessNote:"Regular hill-walking fitness is plenty. Day 3 is long; the rest are half-days.",palette:"dawn",rating:4.9,reviews:286,fairnessDeltaPct:-11,kitSlug:"mardi-kit"},{slug:"poon-hill",name:"Poon Hill & Ghandruk",nameNe:"पुन हिल",region:"Annapurna",days:4,difficulty:"easy",maxAltitude:3210,distanceKm:32,bestMonths:"Year-round · best Oct–Apr",permits:[{name:"Annapurna Conservation Area permit",npr:3e3},{name:"TIMS card",npr:2e3}],category:"trek",priceMode:"from",priceFromNpr:42e3,meetPoint:"Nayapul roadhead, Pokhara",whatThisIsNot:"This is not a private sunrise: on a clear morning the viewpoint is shared with hundreds. It earns its crowds, but they are part of the deal.",operatorId:"op-annapurna",summary:"Nepal's beloved first trek: stone staircases, Gurung villages, and a 32-peak sunrise panorama, no altitude worries.",story:"If the Himalaya has a welcome mat, it's Poon Hill. The trail is the old trade route to Mustang, paved centuries ago with slate steps, threading villages where Gurung grandmothers still dry millet on rooftops. You climb through oak and rhododendron to Ghorepani, set an alarm for 4:45, and walk up Poon Hill with a hundred quiet strangers to watch Dhaulagiri and the whole Annapurna family catch fire. It's the easiest big view on Earth.",highlights:["Sunrise over Dhaulagiri, Annapurna I & Machhapuchhre","The 3,300 stone steps of Ulleri (your legs will remember)","Ghandruk: the most beautiful village museum in Nepal","Family-friendly: kids from ~8 do this happily","Hot lemon-honey-ginger at every stop"],profile:[{day:1,m:1960,label:"Ulleri"},{day:2,m:2860,label:"Ghorepani"},{day:3,m:3210,label:"Poon Hill"},{day:3.5,m:2630,label:"Tadapani"},{day:4,m:1940,label:"Ghandruk"}],itinerary:[{day:1,title:"Pokhara → Nayapul → Ulleri",km:10,hours:"5 h",sleepAltitude:1960,note:"Riverside walking, then the famous staircase. Slow is smooth; smooth is fast."},{day:2,title:"Ulleri → Ghorepani",km:8,hours:"4–5 h",sleepAltitude:2860,note:"Mossy forest with waterfalls all day. Ghorepani's lodges have hot showers and yak-dung stoves."},{day:3,title:"Poon Hill sunrise → Tadapani",km:12,hours:"6 h",sleepAltitude:2630,note:"45 minutes up by headlamp for the panorama, then a ridge walk with Machhapuchhre playing hide-and-seek."},{day:4,title:"Tadapani → Ghandruk → Pokhara",km:6,hours:"3 h",sleepAltitude:822,note:"Descend to Ghandruk for the Gurung museum and lunch with a view, then drive back to Lakeside."}],route:[{lat:28.293,lng:83.703,label:"Nayapul"},{lat:28.337,lng:83.7,label:"Ulleri"},{lat:28.4,lng:83.699,label:"Ghorepani"},{lat:28.387,lng:83.747,label:"Tadapani"},{lat:28.374,lng:83.81,label:"Ghandruk"}],teahouses:!0,safetyNote:"Low altitude, busy trail, lodges everywhere: the main 'risk' is sore knees on the steps. Poles help.",fitnessNote:"If you can climb stairs for an hour with breaks, you can do Poon Hill.",palette:"day",rating:4.7,reviews:521,fairnessDeltaPct:-6,kitSlug:"weekend-kit"},{slug:"langtang-valley",name:"Langtang Valley",nameNe:"लाङटाङ उपत्यका",region:"Langtang",days:7,difficulty:"moderate",maxAltitude:4773,distanceKm:65,bestMonths:"Mar–May · Oct–Nov",permits:[{name:"Langtang National Park entry",npr:3e3},{name:"TIMS card",npr:2e3}],category:"trek",priceMode:"from",priceFromNpr:78e3,meetPoint:"Syabrubesi bus park",whatThisIsNot:"This is not untouched country: you walk through villages rebuilt after the 2015 earthquake, and staying in them is part of what the trek is for.",operatorId:"op-langtang",summary:"The valley of glaciers, a day's drive from Kathmandu: yak cheese, Tamang heritage, and the 360° summit of Kyanjin Ri.",story:"Langtang is the comeback story of Nepali trekking. Rebuilt with extraordinary spirit after 2015, its lodges are warm, its people are glad you came, and its upper valley, a U-shaped glacial corridor under Langtang Lirung, is as dramatic as anywhere in the Khumbu at half the cost and crowds. Climb Kyanjin Ri at dawn, tour the 300-year-old cheese factory, and walk out wishing you'd added two days.",highlights:["Kyanjin Ri (4,773 m): a real summit, no ropes","The ancient yak-cheese factory at Kyanjin Gompa","Tamang villages and water-driven prayer wheels","Every rupee here rebuilds the valley","Closest big trek to Kathmandu: one drive, no flight"],profile:[{day:1,m:1550,label:"Syabrubesi"},{day:2,m:2380,label:"Lama Hotel"},{day:3,m:3430,label:"Langtang"},{day:4,m:3870,label:"Kyanjin Gompa"},{day:5,m:4773,label:"Kyanjin Ri"},{day:5.5,m:3870},{day:6,m:2380,label:"Lama Hotel"},{day:7,m:1400,label:"Kathmandu"}],itinerary:[{day:1,title:"Drive Kathmandu → Syabrubesi",sleepAltitude:1550,note:"7–8 hours over the Trisuli gorge roads. Sleep early; the trail starts at the bridge."},{day:2,title:"Syabrubesi → Lama Hotel",km:11,hours:"6 h",sleepAltitude:2380,note:"Riverside forest all day: langurs, honey hives on cliffs, one steady climb."},{day:3,title:"Lama Hotel → Langtang Village",km:15,hours:"6–7 h",sleepAltitude:3430,note:"You pass the memorial to the old village, walk it quietly, and arrive into the rebuilt one, brighter than ever."},{day:4,title:"Langtang → Kyanjin Gompa",km:7,hours:"3–4 h",sleepAltitude:3870,note:"Short day past mani walls longer than football pitches. Afternoon: monastery, bakery, cheese factory."},{day:5,title:"Kyanjin Ri sunrise, rest day",km:6,hours:"5 h",sleepAltitude:3870,note:"Up at 4:30 for the ridge: Langtang Lirung's icefalls glow pink across the valley. Down for pancakes."},{day:6,title:"Kyanjin → Lama Hotel",km:19,hours:"7 h",sleepAltitude:2380,note:"Long, lovely descent: the valley replays itself in reverse."},{day:7,title:"Walk out & drive to Kathmandu",km:11,hours:"4 h + drive",sleepAltitude:1400,note:"Morning walk to Syabrubesi, jeep home, dinner in Thamel."}],route:[{lat:28.16,lng:85.348,label:"Syabrubesi"},{lat:28.183,lng:85.43,label:"Lama Hotel"},{lat:28.214,lng:85.512,label:"Langtang"},{lat:28.211,lng:85.567,label:"Kyanjin"}],teahouses:!0,safetyNote:"The jump from Lama Hotel to Langtang Village is the big altitude day. Hydrate and go slow. Kyanjin Ri is optional and weather-dependent; your guide decides at dawn.",fitnessNote:"Comfortable 6-hour walking days with one optional steep summit morning.",palette:"forest",rating:4.8,reviews:198,fairnessDeltaPct:-9,kitSlug:"langtang-kit"},{slug:"manaslu-circuit",name:"Manaslu Circuit",nameNe:"मनास्लु परिक्रमा",region:"Manaslu",days:13,difficulty:"strenuous",maxAltitude:5106,distanceKm:122,bestMonths:"Mar–Apr · Oct–Nov",permits:[{name:"Manaslu restricted-area permit",npr:13300},{name:"MCAP conservation entry",npr:3e3},{name:"Annapurna Conservation Area permit",npr:3e3}],category:"trek",priceMode:"from",priceFromNpr:198e3,meetPoint:"Machha Khola roadhead",whatThisIsNot:"This is not a solo-friendly route: the restricted permit requires a registered guide and a minimum group of two, and teahouses are a notch simpler than Annapurna's.",operatorId:"op-expedition",badges:["restricted"],summary:"The connoisseur's circuit: a restricted-area loop around the world's eighth-highest peak, wilder and quieter than its famous neighbours.",story:"Manaslu is what the Annapurna Circuit was thirty years ago, protected by a restricted-area permit that keeps the trail uncrowded and guides mandatory. The Budhi Gandaki gorge swallows you for days (bridges over chasms, villages stacked like swallow nests) before the valley opens into Tibetan-Buddhist highlands at Samagaon, under Manaslu's double summit. Larkya La is a serious pass with a serious sunrise. You earn this one.",highlights:["Larkya La (5,106 m): the finest pass crossing in Nepal","Restricted-area quiet: more yaks than trekkers","Pungyen Gompa day-hike under Manaslu's east face","Samdo village: one valley from the Tibet border","Old-growth forest descent into Bimthang"],profile:[{day:1,m:869,label:"Machha Khola"},{day:2,m:1340,label:"Jagat"},{day:3,m:1860,label:"Deng"},{day:4,m:2630,label:"Namrung"},{day:5,m:3530,label:"Samagaon"},{day:6,m:4060,label:"Pungyen"},{day:6.5,m:3530},{day:7,m:3875,label:"Samdo"},{day:8,m:3875,label:"Samdo (rest)"},{day:9,m:4460,label:"Dharamsala"},{day:10,m:5106,label:"Larkya La"},{day:10.5,m:3720,label:"Bimthang"},{day:11,m:2300,label:"Tilije"},{day:12,m:1400,label:"Kathmandu"},{day:13,m:1400,label:"Buffer day"}],itinerary:[{day:1,title:"Drive Kathmandu → Machha Khola",sleepAltitude:869,note:"A bumpy, beautiful 8-hour jeep ride into the Budhi Gandaki valley."},{day:2,title:"Machha Khola → Jagat",km:14,hours:"6 h",sleepAltitude:1340,note:"Hot springs at Tatopani (the name literally means 'hot water'), then slate-roofed Jagat, your permit checkpoint."},{day:3,title:"Jagat → Deng",km:16,hours:"6–7 h",sleepAltitude:1860,note:"The gorge narrows to a slot; you cross it four times on high bridges. Bee hives hang under cliffs."},{day:4,title:"Deng → Namrung",km:17,hours:"6–7 h",sleepAltitude:2630,note:"Culture changes mid-day: chortens, mani walls, the first long views to Ganesh Himal."},{day:5,title:"Namrung → Samagaon",km:17,hours:"7 h",sleepAltitude:3530,note:"Through Lho (monastery worth every step) with Manaslu's twin peaks ahead all afternoon."},{day:6,title:"Acclimatisation: Pungyen Gompa",km:8,hours:"5 h",sleepAltitude:3530,note:"A hidden hermitage under the east face glacier. Back for butter tea."},{day:7,title:"Samagaon → Samdo",km:8,hours:"4 h",sleepAltitude:3875,note:"Short, breathless, gorgeous. Samdo is the last village before the pass."},{day:8,title:"Samdo rest & ridge hike",km:6,hours:"4 h",sleepAltitude:3875,note:"Optional hike toward the Tibet-border ridge for acclimatisation. Yak caravans everywhere."},{day:9,title:"Samdo → Dharamsala",km:7,hours:"4 h",sleepAltitude:4460,note:"High camp. Early dinner, kit check, 3 a.m. alarm."},{day:10,title:"Larkya La (5,106 m) → Bimthang",km:15,hours:"9–10 h",sleepAltitude:3720,note:"The big one: moraine ridges by headlamp, prayer flags at the pass, then a vast glacier basin descent into rhododendron forest."},{day:11,title:"Bimthang → Tilije",km:19,hours:"7 h",sleepAltitude:2300,note:"Down through old-growth pine and farmland: the warm air feels tropical."},{day:12,title:"Tilije → Dharapani → drive to Kathmandu",sleepAltitude:1400,note:"Join the Annapurna trail briefly, then jeep out via Besisahar."},{day:13,title:"Kathmandu buffer day",sleepAltitude:1400,note:"Built-in weather/contingency day. If unused: Bhaktapur, momos, massage."}],route:[{lat:28.327,lng:84.892,label:"Machha Khola"},{lat:28.366,lng:84.898,label:"Jagat"},{lat:28.483,lng:84.866,label:"Deng"},{lat:28.577,lng:84.625,label:"Samagaon"},{lat:28.64,lng:84.633,label:"Samdo"},{lat:28.66,lng:84.56,label:"Larkya La"},{lat:28.643,lng:84.495,label:"Bimthang"},{lat:28.52,lng:84.391,label:"Dharapani"}],teahouses:!0,safetyNote:"A restricted region: solo trekking is not permitted and a licensed guide is mandatory, which is exactly how we operate anyway. Larkya day is long and cold; we require the Samdo rest day and carry a satellite communicator.",fitnessNote:"Strenuous: a 9–10 hour pass day at altitude after a week of 6–7 hour days. Train with back-to-back hill days beforehand.",palette:"dusk",rating:4.9,reviews:143,fairnessDeltaPct:-4,kitSlug:"everest-kit"},{slug:"rara-lake",name:"Rara Lake",nameNe:"रारा ताल",region:"Karnali",days:5,difficulty:"easy",maxAltitude:3700,distanceKm:26,bestMonths:"Apr–Jun · Sep–Nov",permits:[{name:"Rara National Park entry",npr:3e3}],category:"trek",priceMode:"from",priceFromNpr:96e3,meetPoint:"Talcha airstrip, Mugu",whatThisIsNot:"This is not an easy add-on: reaching Mugu costs real time or a small plane, and services around the lake stay basic.",operatorId:"op-west",summary:"Nepal's biggest lake, hidden in its far-west pine forests: two flights, a short walk, and a blue you won't believe.",story:"Rara is the trip for people who think they've seen Nepal. Two small flights hop you to Talcha airstrip in the Karnali (the country's emptiest, highest-poverty, most beautiful province) and a half-day walk delivers you to a three-by-five-kilometre lake that changes colour hourly: slate at dawn, turquoise at noon, ink by dusk. Horses graze the meadows. Phones stop working. That's the feature, not the bug.",highlights:["The 'Queen of Lakes': 167 m deep, impossibly blue","Murma Top sunrise over the whole lake basin","Snow-pine forests full of musk deer and red panda (if you're lucky)","Boating with the national park's wooden ferry","True far-west Nepal: almost zero tourists"],profile:[{day:1,m:150,label:"Nepalgunj"},{day:2,m:2990,label:"Rara Lake"},{day:3,m:3700,label:"Murma Top"},{day:3.5,m:2990},{day:4,m:2990,label:"Lake circuit"},{day:5,m:1400,label:"Kathmandu"}],itinerary:[{day:1,title:"Fly Kathmandu → Nepalgunj",sleepAltitude:150,note:"Overnight in the Terai heat: good daal bhaat, early night for the dawn flight."},{day:2,title:"Fly to Talcha → walk to Rara",km:6,hours:"3 h",sleepAltitude:2990,note:"A 35-minute mountain flight, then an easy forest walk to the lakeshore lodges."},{day:3,title:"Murma Top sunrise",km:9,hours:"5–6 h",sleepAltitude:2990,note:"The classic viewpoint: the whole lake below, Saipal's snows on the horizon. Picnic lunch by the water."},{day:4,title:"Lake circuit day",km:11,hours:"5 h",sleepAltitude:2990,note:"Flat, fragrant pine-needle trail around the shore. Ferry ride optional, swimming brave."},{day:5,title:"Fly out via Nepalgunj",sleepAltitude:1400,note:"Talcha → Nepalgunj → Kathmandu. Phones return; you may resent them."}],route:[{lat:29.512,lng:82.146,label:"Talcha"},{lat:29.53,lng:82.09,label:"Rara Lake"},{lat:29.555,lng:82.06,label:"Murma Top"}],teahouses:!0,safetyNote:"Remote rather than risky: flights are weather-dependent (we hold buffer seats), and facilities are simple. Cash only beyond Nepalgunj. We'll remind you.",fitnessNote:"Easy walking at moderate altitude; the Murma climb is the only real effort.",palette:"lake",rating:4.8,reviews:87,fairnessDeltaPct:3,kitSlug:"langtang-kit"},{slug:"gokyo-lakes",name:"Gokyo Lakes",nameNe:"गोक्यो ताल",region:"Khumbu",days:12,difficulty:"demanding",maxAltitude:5357,distanceKm:92,bestMonths:"Mar–May · Oct–Nov",permits:[{name:"Sagarmatha National Park entry",npr:3e3},{name:"Khumbu Pasang Lhamu municipality fee",npr:2e3}],category:"trek",priceMode:"from",priceFromNpr:168e3,meetPoint:"Lukla airstrip",whatThisIsNot:"This is not the shortcut to Everest views: Gokyo Ri is as breathless as Kala Patthar, and the Cho La option is a genuine pass, not a detour.",operatorId:"op-khumbu",summary:"The Everest region's quieter half: a string of six sacred turquoise lakes under Cho Oyu, and a sunrise from Gokyo Ri that rivals Kala Patthar with a tenth of the crowd.",story:"Most people walk to Base Camp and never know what they missed one valley west. The Gokyo trail leaves the Everest highway at Namche and climbs the Dudh Koshi's far branch, past Dole and Machhermo, to a chain of glacial lakes so blue they look retouched. The climb up Gokyo Ri at dawn gives you four eight-thousanders in one sweep, Everest, Lhotse, Makalu and Cho Oyu, above the largest glacier in Nepal, the Ngozumpa. It is the same altitude discipline as Base Camp, with more lake and less queue.",highlights:["Sunrise from Gokyo Ri (5,357 m): four 8,000ers at once","The six Gokyo lakes, sacred and glacier-fed","The Ngozumpa, the longest glacier in Nepal","Cho Oyu (8,188 m) filling the head of the valley","Far fewer trekkers than the Base Camp trail"],profile:[{day:1,m:2860,label:"Lukla"},{day:2,m:3440,label:"Namche"},{day:3,m:3440,label:"Acclimatise"},{day:4,m:4040,label:"Dole"},{day:5,m:4470,label:"Machhermo"},{day:6,m:4790,label:"Gokyo"},{day:7,m:5357,label:"Gokyo Ri"},{day:8,m:4470,label:"Machhermo"},{day:9,m:3440,label:"Namche"},{day:10,m:2860,label:"Lukla"}],itinerary:[{day:1,title:"Fly to Lukla, walk to Phakding",km:8,hours:"3–4 h",sleepAltitude:2610,note:"The tilted runway, then a gentle descent along the Dudh Koshi to start adapting."},{day:2,title:"Phakding → Namche Bazaar",km:11,hours:"6 h",sleepAltitude:3440,note:"Suspension bridges and the long Namche hill into the Sherpa capital."},{day:3,title:"Acclimatisation in Namche",km:5,hours:"3 h",sleepAltitude:3440,note:"Hike high to the Everest View Hotel, sleep low. The golden rule starts here."},{day:4,title:"Namche → Dole",km:12,hours:"5–6 h",sleepAltitude:4040,note:"Leave the Base Camp crowds at Sanasa and climb the quiet Gokyo valley."},{day:5,title:"Dole → Machhermo",km:7,hours:"4 h",sleepAltitude:4470,note:"Short and slow on purpose. Afternoon rest at the IPPG altitude-aid post."},{day:6,title:"Machhermo → Gokyo",km:7,hours:"4–5 h",sleepAltitude:4790,note:"Past the first two lakes to Gokyo village on the third, beneath the Ngozumpa."},{day:7,title:"Gokyo Ri sunrise + fourth & fifth lakes",km:9,hours:"6 h",sleepAltitude:4790,note:"Pre-dawn climb to 5,357 m for the four-summit panorama, then explore the upper lakes."},{day:8,title:"Gokyo → Machhermo → Dole",km:14,hours:"6 h",sleepAltitude:4040,note:"A long, satisfying descent into thicker air."},{day:9,title:"Dole → Namche",km:12,hours:"5–6 h",sleepAltitude:3440,note:"Back to bakeries and a hot shower."},{day:10,title:"Namche → Lukla",km:19,hours:"7 h",sleepAltitude:2860,note:"The last bridges and one final hill to Lukla."},{day:11,title:"Buffer day for weather",sleepAltitude:2860,note:"Held in case Lukla flights are delayed, the most common Khumbu hiccup."},{day:12,title:"Fly back to Kathmandu",sleepAltitude:1400,note:"Morning flight out, hot shower, big dinner."}],route:[{lat:27.687,lng:86.731,label:"Lukla"},{lat:27.804,lng:86.711,label:"Namche"},{lat:27.866,lng:86.726,label:"Dole"},{lat:27.905,lng:86.708,label:"Machhermo"},{lat:27.955,lng:86.694,label:"Gokyo"},{lat:27.962,lng:86.689,label:"Gokyo Ri"}],teahouses:!0,safetyNote:"Same altitude maths as Base Camp: no more than ~500 m of sleeping gain a day above 3,000 m, a full rest day in Namche, and your guide carries a pulse oximeter with twice-daily checks.",fitnessNote:"Comfortable on 5–7 hour days with a daypack, back to back. No technical skill, just patience with the thin air.",palette:"lake",rating:4.8,reviews:0,fairnessDeltaPct:-2,kitSlug:"everest-kit"},{slug:"upper-mustang",name:"Upper Mustang",nameNe:"माथिल्लो मुस्ताङ",region:"Mustang",days:11,difficulty:"moderate",maxAltitude:3840,distanceKm:110,bestMonths:"Mar–Nov (rain-shadow, trekkable in monsoon)",permits:[{name:"Upper Mustang restricted area permit (10 days)",npr:67500},{name:"Annapurna Conservation Area permit",npr:3e3}],category:"trek",priceMode:"from",priceFromNpr:295e3,meetPoint:"Jomsom airstrip",whatThisIsNot:"This is not a budget trek: the restricted permit alone costs USD 500 for ten days, and the walled kingdom is wind, dust and rock, not forest and rhododendron.",operatorId:"op-expedition",badges:["restricted"],summary:"The forbidden kingdom of Lo: a walled medieval capital, sky-caves and ochre canyons in the rain shadow behind Annapurna and Dhaulagiri, where Tibetan Buddhism lives on untouched.",story:"Closed to outsiders until 1992 and still capped by a costly permit, Upper Mustang is the old Kingdom of Lo, a slice of the Tibetan plateau that happens to sit inside Nepal. The trail north from Kagbeni leaves the green behind and enters a desert of wind-carved cliffs, eroded mani walls and whitewashed villages, climbing to the still-walled capital of Lo Manthang and its 15th-century monasteries. Because it lives in the Himalaya's rain shadow, it is one of the few great treks you can do through the monsoon.",highlights:["The walled city of Lo Manthang and its royal palace","Ochre canyons and ancient cliff sky-caves","15th-century Tibetan monasteries with original murals","A genuine rain-shadow route: dry through the monsoon","Apple orchards and whitewashed Loba villages"],profile:[{day:1,m:2720,label:"Jomsom"},{day:2,m:2810,label:"Kagbeni"},{day:3,m:3050,label:"Chele"},{day:4,m:3570,label:"Geling"},{day:5,m:3560,label:"Tsarang"},{day:6,m:3840,label:"Lo Manthang"},{day:7,m:3840,label:"Explore"},{day:9,m:3050,label:"Chele"},{day:10,m:2720,label:"Jomsom"}],itinerary:[{day:1,title:"Fly Pokhara → Jomsom, walk to Kagbeni",km:9,hours:"3–4 h",sleepAltitude:2810,note:"The dramatic Kali Gandaki flight, then up to the gateway village of Kagbeni where the restricted zone begins."},{day:2,title:"Kagbeni → Chele",km:16,hours:"6 h",sleepAltitude:3050,note:"Permits checked, you cross into Upper Mustang and the green vanishes into red rock."},{day:3,title:"Chele → Geling",km:16,hours:"6–7 h",sleepAltitude:3570,note:"Two passes and the first painted chortens of the high desert."},{day:4,title:"Geling → Tsarang",km:15,hours:"6 h",sleepAltitude:3560,note:"Over the Nyi La and past the huge red gompa of Ghami."},{day:5,title:"Tsarang → Lo Manthang",km:14,hours:"5 h",sleepAltitude:3840,note:"The walled capital appears across the plain. Enter through the single gate."},{day:6,title:"Explore Lo Manthang",km:8,hours:"5 h",sleepAltitude:3840,note:"The royal palace, Jampa and Thubchen monasteries, and a day-ride to the Chhoser sky-caves."},{day:7,title:"Lo Manthang → Dhakmar",km:18,hours:"6–7 h",sleepAltitude:3520,note:"A different way back past the crimson cliffs of Dhakmar and the Lo Gekar monastery."},{day:8,title:"Dhakmar → Chele",km:17,hours:"6 h",sleepAltitude:3050,note:"Retracing south as the canyons soften."},{day:9,title:"Chele → Jomsom",km:19,hours:"7 h",sleepAltitude:2720,note:"Back to Kagbeni and Jomsom, often into the famous afternoon wind."},{day:10,title:"Fly Jomsom → Pokhara",sleepAltitude:820,note:"Morning flight out before the wind picks up."},{day:11,title:"Pokhara → Kathmandu",sleepAltitude:1400,note:"Lakeside rest or the short hop back to Kathmandu."}],route:[{lat:28.782,lng:83.723,label:"Jomsom"},{lat:28.838,lng:83.787,label:"Kagbeni"},{lat:28.903,lng:83.832,label:"Chele"},{lat:28.985,lng:83.872,label:"Geling"},{lat:29.183,lng:83.952,label:"Tsarang"},{lat:29.18,lng:83.963,label:"Lo Manthang"}],teahouses:!0,safetyNote:"Altitude is gentle here, but the restricted permit requires a registered guide and a minimum of two trekkers, both included. Afternoons bring fierce valley wind; we walk mornings.",fitnessNote:"Moderate days at modest altitude on dusty jeep-track and trail. The challenge is distance and wind, not steepness.",palette:"lux",rating:4.9,reviews:0,fairnessDeltaPct:-1,kitSlug:"annapurna-kit"},{slug:"khopra-danda",name:"Khopra Danda",nameNe:"खोप्रा डाँडा",region:"Annapurna",days:7,difficulty:"moderate",maxAltitude:3660,distanceKm:42,bestMonths:"Mar–May · Oct–Nov",permits:[{name:"Annapurna Conservation Area permit",npr:3e3}],category:"trek",priceMode:"from",priceFromNpr:92e3,meetPoint:"Nayapul roadhead, Pokhara",whatThisIsNot:"This is not a serviced honeypot route: the community lodges are simple, hot water is a bucket, and that is exactly the point.",operatorId:"op-annapurna",summary:"A community-built ridge trek that swaps Poon Hill's crowds for a balcony seat in front of Dhaulagiri and Annapurna South, with an optional dawn climb to the sacred Khayer Lake.",story:"Khopra Danda was built by the villages along it, a string of community-owned lodges on a high ridge that almost nobody walks. You climb through rhododendron and oak above Ghandruk, and where the Poon Hill crowds turn back, you keep going onto an open spur that puts the eighth-highest mountain on earth, Dhaulagiri, directly across the gorge. The strong-legged add a pre-dawn push to Khayer Lake at 4,660 m, a sacred tarn under Annapurna South. Your fees stay in the valley.",highlights:["Dhaulagiri (8,167 m) face-on across the Kali Gandaki","Community-owned lodges: your money stays local","Rhododendron forest in spring, ablaze","Optional sunrise at sacred Khayer Lake (4,660 m)","The crowd-free alternative to Poon Hill"],profile:[{day:1,m:1940,label:"Ghandruk"},{day:2,m:2630,label:"Tadapani"},{day:3,m:3420,label:"Dobato"},{day:4,m:3660,label:"Khopra Danda"},{day:4.5,m:4660,label:"Khayer Lake"},{day:5,m:2210,label:"Swanta"},{day:6,m:1070,label:"Tatopani"}],itinerary:[{day:1,title:"Drive to Nayapul, walk to Ghandruk",km:8,hours:"4–5 h",sleepAltitude:1940,note:"Up stone stairs to the beautiful Gurung village of Ghandruk, Annapurna South overhead."},{day:2,title:"Ghandruk → Tadapani",km:8,hours:"4–5 h",sleepAltitude:2630,note:"Into deep rhododendron forest, loud with birds."},{day:3,title:"Tadapani → Dobato",km:7,hours:"5 h",sleepAltitude:3420,note:"Quieter every step. A short side-climb to Mulde viewpoint at dusk."},{day:4,title:"Dobato → Khopra Danda",km:6,hours:"4 h",sleepAltitude:3660,note:"Onto the open ridge with Dhaulagiri filling the sky across the gorge."},{day:5,title:"Optional Khayer Lake, then to Swanta",km:13,hours:"7–8 h",sleepAltitude:2210,note:"Pre-dawn return trip to the sacred lake at 4,660 m, then a long drop to Swanta village."},{day:6,title:"Swanta → Tatopani",km:9,hours:"4–5 h",sleepAltitude:1070,note:"Down to the hot springs of Tatopani on the Kali Gandaki. Soak earned."},{day:7,title:"Drive back to Pokhara",sleepAltitude:820,note:"Scenic road down the gorge to Lakeside."}],route:[{lat:28.376,lng:83.808,label:"Ghandruk"},{lat:28.404,lng:83.792,label:"Tadapani"},{lat:28.43,lng:83.764,label:"Dobato"},{lat:28.452,lng:83.712,label:"Khopra Danda"},{lat:28.487,lng:83.69,label:"Khayer Lake"}],teahouses:!0,safetyNote:"Moderate altitude, but the optional Khayer Lake push to 4,660 m is a big single-day gain, do it only if you have slept well at Khopra, and turn back without ego if your head argues.",fitnessNote:"Solid hill fitness for stone-stair climbs and one long descent day. No exposure, no technical ground.",palette:"alpenglow",rating:4.8,reviews:0,fairnessDeltaPct:-3,kitSlug:"annapurna-kit"},{slug:"kanchenjunga-bc",name:"Kanchenjunga Base Camp",nameNe:"कञ्चनजङ्घा आधार शिविर",region:"Kanchenjunga",days:15,difficulty:"strenuous",maxAltitude:5140,distanceKm:220,bestMonths:"Mar–May · Oct–Nov",permits:[{name:"Kanchenjunga restricted-area permit (4 weeks)",npr:13e3},{name:"Kanchenjunga Conservation Area (KCAP)",npr:2e3}],category:"trek",priceMode:"from",priceFromNpr:365e3,meetPoint:"Bhadrapur airport, jeep to Taplejung",whatThisIsNot:"This is not a casual undertaking: three weeks, basic food and lodging, long jeep approaches, and help is far away if anything goes wrong.",operatorId:"op-expedition",badges:["restricted"],summary:"Nepal's wild far-eastern corner: just over two weeks to the north base camp of the world's third-highest mountain, through rhododendron jungle, Limbu and Tibetan villages, and almost no other trekkers.",story:"Kanchenjunga sits in the remote north-east, hard against Sikkim, and getting there is half the trek: a long drive or flight east, then days through leech-warm jungle and terraced Limbu country before the land tilts up toward the high Ghunsa valley. The north base camp at Pangpema, 5,140 m, faces a two-kilometre wall of ice. This is a restricted area, so a registered guide and a partner are required, and that is exactly why the trail stays empty and the villages stay themselves.",highlights:["Pangpema (5,140 m) under Kanchenjunga's north face","Two weeks with almost no other trekkers","Limbu and Tibetan villages largely untouched by tourism","Rhododendron and old-growth forest of the conservation area","Red panda country, if you are very lucky and very quiet"],profile:[{day:1,m:1820,label:"Taplejung"},{day:2,m:1640,label:"Sekathum"},{day:5,m:3430,label:"Ghunsa"},{day:7,m:4145,label:"Kambachen"},{day:9,m:4780,label:"Lhonak"},{day:10,m:5140,label:"Pangpema"},{day:13,m:1860,label:"Tapethok"}],itinerary:[{day:1,title:"Fly to Bhadrapur, drive to Taplejung",hours:"8–9 h drive",sleepAltitude:1820,note:"The long journey east into Limbu country. The remoteness is the point."},{day:2,title:"Taplejung → Sekathum",km:18,hours:"6–7 h",sleepAltitude:1640,note:"Down to the Tamur and up its side-valley into thick subtropical forest."},{day:3,title:"Sekathum → Amjilosa",km:12,hours:"6 h",sleepAltitude:2510,note:"Steep climbing beside the Ghunsa Khola, waterfalls everywhere."},{day:4,title:"Amjilosa → Gyabla",km:11,hours:"5–6 h",sleepAltitude:2730,note:"Into the rhododendron and the first Tibetan-style village."},{day:5,title:"Gyabla → Ghunsa",km:10,hours:"5 h",sleepAltitude:3430,note:"The lovely Tibetan village of Ghunsa, hub of the upper valley. Rest day next."},{day:6,title:"Acclimatisation day in Ghunsa",km:5,hours:"3 h",sleepAltitude:3430,note:"Hike high to a viewpoint, sleep low. Visit the monastery and the micro-hydro."},{day:7,title:"Ghunsa → Kambachen",km:10,hours:"6 h",sleepAltitude:4145,note:"Above the treeline now, past a landslide-prone slope your guide will time carefully."},{day:8,title:"Acclimatisation in Kambachen",km:4,hours:"3 h",sleepAltitude:4145,note:"A short walk toward Jannu's amphitheatre, then rest. Altitude is the whole game now."},{day:9,title:"Kambachen → Lhonak",km:9,hours:"5–6 h",sleepAltitude:4780,note:"A high, wild walk to the bleak and beautiful basin of Lhonak."},{day:10,title:"Pangpema (North Base Camp) and back",km:14,hours:"7–8 h",sleepAltitude:4780,note:"The day it is all for: out to 5,140 m under the north face, then back to Lhonak to sleep."},{day:11,title:"Lhonak → Ghunsa",km:19,hours:"7 h",sleepAltitude:3430,note:"A long, joyful descent back into the trees."},{day:12,title:"Ghunsa → Amjilosa",km:21,hours:"7–8 h",sleepAltitude:2510,note:"Retracing the green valley south."},{day:13,title:"Amjilosa → Sekathum → Tapethok",km:20,hours:"7 h",sleepAltitude:1860,note:"Out of the side-valley back toward the Tamur road head."},{day:14,title:"Drive Tapethok → Birtamod",hours:"9–10 h drive",sleepAltitude:300,note:"The long road back to the plains."},{day:15,title:"Fly Bhadrapur → Kathmandu",sleepAltitude:1400,note:"Morning flight back to the capital. A genuinely remote trek, completed."}],route:[{lat:27.359,lng:87.677,label:"Taplejung"},{lat:27.503,lng:87.842,label:"Sekathum"},{lat:27.661,lng:87.939,label:"Ghunsa"},{lat:27.713,lng:87.952,label:"Kambachen"},{lat:27.779,lng:88.001,label:"Lhonak"},{lat:27.804,lng:88.048,label:"Pangpema"}],teahouses:!0,safetyNote:"Remote and high: this is a restricted area needing a registered guide and a two-trekker minimum, both included. Rescue is hours or days away, so the itinerary is acclimatisation-first and your guide carries a pulse oximeter and a comms device.",fitnessNote:"Real hill fitness and stamina for two weeks of back-to-back days, some of them long. No technical climbing, but the remoteness demands self-sufficiency.",palette:"dawn",rating:4.9,reviews:0,fairnessDeltaPct:0,kitSlug:"everest-kit"}];e.s(["TREKS",0,a,"getTrek",0,e=>a.find(a=>a.slug===e)])},83597,e=>{"use strict";let a=[{id:"g1",slug:"pasang-norbu-sherpa",name:"Pasang Norbu Sherpa",home:"Khumjung, Khumbu",languages:["English","Nepali","Sherpa"],specialties:["High-altitude treks","Photography pacing","First-timers at altitude"],regions:["Khumbu","Manaslu"],treksLed:214,yearsExp:14,rating:4.9,reviews:186,pricePerDayNpr:4800,bio:"Pasang grew up two ridges from Everest View and has walked to Base Camp more than two hundred times, yet clients say he shows them the Khumbu like it's his first time too. He's a stickler for acclimatisation schedules, carries a pulse oximeter religiously, and knows which lodge in Dingboche bakes apple pie on Tuesdays.",quote:"The mountain decides the schedule. My job is making sure you're strong enough to hear it.",certifications:["NMA Trekking Guide License","Wilderness First Responder","KEEP Altitude Training"],verified:!0,trustScore:98,responseMins:12,pace:"steady",palette:"dawn"},{id:"g2",slug:"anita-gurung",name:"Anita Gurung",home:"Ghandruk, Kaski",languages:["English","Nepali","Gurung","basic German"],specialties:["Family treks","Village culture","Women's trekking groups"],regions:["Annapurna"],treksLed:156,yearsExp:9,rating:5,reviews:142,pricePerDayNpr:4200,bio:"One of the first licensed women guides from Ghandruk itself, Anita leads the Annapurna foothills like a walking introduction to her own family: expect tea stops at her aunt's lodge and a millet-grinding lesson if you ask. Parents request her by name: she has a sixth sense for a tired eight-year-old.",quote:"Every trail here passes someone's kitchen. I just make sure the door opens.",certifications:["NMA Trekking Guide License","First Aid (NRCS)","Empowering Women of Nepal alumna"],verified:!0,trustScore:99,responseMins:8,pace:"relaxed",palette:"day"},{id:"g3",slug:"tenzing-lama",name:"Tenzing Lama",home:"Briddim, Rasuwa",languages:["English","Nepali","Tamang","Tibetan"],specialties:["Langtang heritage","Buddhist culture","Slow trekking"],regions:["Langtang"],treksLed:121,yearsExp:11,rating:4.9,reviews:97,pricePerDayNpr:4e3,bio:"Tenzing rebuilt his family lodge after 2015 and then went back to guiding because, he says, the valley heals fastest when it's walked. He reads the gompa murals like newspapers and pours the best butter tea on the trail. Choose him if you want the why of Langtang, not just the where.",quote:"People come for Langtang Lirung. They come back for the people under it.",certifications:["NMA Trekking Guide License","First Aid (NRCS)","Langtang Heritage Fund member"],verified:!0,trustScore:97,responseMins:20,pace:"relaxed",palette:"forest"},{id:"g4",slug:"mingma-dorje-sherpa",name:"Mingma Dorje Sherpa",home:"Phortse, Khumbu",languages:["English","Nepali","Sherpa","Japanese"],specialties:["Fast alpine itineraries","Expedition prep","Repeat clients"],regions:["Khumbu","Manaslu","Langtang"],treksLed:188,yearsExp:16,rating:4.8,reviews:164,pricePerDayNpr:5500,bio:"A former expedition climbing Sherpa with two 8,000 m summits, Mingma now prefers trekking pace, though his idea of 'optional morning hike' has a reputation. Book him for Manaslu or a fast EBC if you're fit, trained, and want the mountains explained by someone who has slept on them.",quote:"Strong legs are common. Strong judgement is what I teach.",certifications:["NMA Guide License","NNMGA Aspirant Mountain Guide","Wilderness Advanced First Aid"],verified:!0,trustScore:96,responseMins:35,pace:"fast",palette:"dusk"},{id:"g5",slug:"sarita-thapa-magar",name:"Sarita Thapa Magar",home:"Pokhara, Kaski",languages:["English","Nepali","Hindi"],specialties:["Budget groups","Student trips","Sunrise missions"],regions:["Annapurna"],treksLed:98,yearsExp:6,rating:4.8,reviews:88,pricePerDayNpr:3500,bio:"Sarita runs the most cheerful budget treks out of Pokhara: shared jeeps, the lodges with the best daal bhaat refills, and a playlist for the Ulleri steps. She's the reason half the hostels in Lakeside recommend us. Backpackers: this is your person.",quote:"Cheap doesn't mean careless. It means I know where the value hides.",certifications:["NMA Trekking Guide License","First Aid (NRCS)"],verified:!0,trustScore:95,responseMins:6,pace:"steady",palette:"alpenglow"},{id:"g6",slug:"karma-tsering-bhote",name:"Karma Tsering Bhote",home:"Samagaon, Gorkha",languages:["English","Nepali","Tibetan"],specialties:["Manaslu restricted area","High passes","Yak-route logistics"],regions:["Manaslu"],treksLed:87,yearsExp:12,rating:4.9,reviews:61,pricePerDayNpr:5200,bio:"Karma was born under Manaslu's east face and has crossed Larkya La in every month it's crossable. He handles the restricted-area paperwork himself, knows every lodge-keeper by childhood nickname, and carries a satellite communicator as standard. The circuit is his commute.",quote:"On Larkya day I have one rule: we move like the slowest person feels.",certifications:["NMA Trekking Guide License","Restricted Area Endorsement","Wilderness First Responder"],verified:!0,trustScore:98,responseMins:45,pace:"steady",palette:"dusk"},{id:"g7",slug:"bishal-adhikari",name:"Bishal Adhikari",home:"Kathmandu",languages:["English","Nepali","French","Spanish"],specialties:["City heritage","Food walks","Day adventures"],regions:["Kathmandu Valley","Annapurna"],treksLed:132,yearsExp:8,rating:4.9,reviews:173,pricePerDayNpr:3800,bio:"Bishal is the guide for the days you're not trekking: Patan's hidden courtyards, Bhaktapur at dawn before the buses, the newari kitchen where you'll eat the trip's best meal. A trained conservation architect who defected to storytelling. Bring questions.",quote:"Kathmandu isn't chaotic. It's seven cities talking at once, and I speak all of them.",certifications:["City Guide License (NATTA)","Heritage Conservation Cert.","First Aid (NRCS)"],verified:!0,trustScore:97,responseMins:5,pace:"relaxed",palette:"lux"},{id:"g8",slug:"dawa-phuti-sherpa",name:"Dawa Phuti Sherpa",home:"Lukla, Khumbu",languages:["English","Nepali","Sherpa","Mandarin"],specialties:["Luxury treks","Heli-assisted itineraries","Private groups"],regions:["Khumbu","Annapurna","Karnali"],treksLed:104,yearsExp:10,rating:5,reviews:76,pricePerDayNpr:7500,bio:"Dawa runs the white-glove end of the trail: the lodges with duvets and gas heaters, helicopter contingencies pre-booked, oxygen and a private porter ratio of one-to-one. Half her clients are CEOs; the other half are their parents. Discretion absolute, sunrise timing impeccable.",quote:"Luxury at altitude is simple: it's margin. Margin of time, oxygen, and comfort.",certifications:["NMA Guide License","Wilderness First Responder","Heli-evac coordination cert."],verified:!0,trustScore:99,responseMins:10,pace:"relaxed",palette:"lux"}];e.s(["GUIDES",0,a,"getGuide",0,e=>a.find(a=>a.id===e||a.slug===e)])}]);